@Service
public class CustomerPaymentService{
 private final CustomerOrderRepository orders; private final CustomerOrderStatusHistoryRepository orderHistory; private final PaymentMethodConfigurationRepository methods; private final CustomerPaymentRepository payments; private final PaymentAttemptRepository attempts; private final PaymentEventRepository events; private final PaymentStatusHistoryRepository histories; private final ManualPaymentSubmissionRepository manualSubs; private final PaymentReviewRepository reviews; private final PaymentRefundRepository refunds; private final PaymentReconciliationRecordRepository reconciliations; private final FinancialAccountRepository accounts; private final AccountLedgerEntryRepository ledgers; private final PaymentGatewayAdapter gateway; @Autowired(required=false) private CustomerNotificationService notifications;
 public CustomerPaymentService(CustomerOrderRepository orders,CustomerOrderStatusHistoryRepository orderHistory,PaymentMethodConfigurationRepository methods,CustomerPaymentRepository payments,PaymentAttemptRepository attempts,PaymentEventRepository events,PaymentStatusHistoryRepository histories,ManualPaymentSubmissionRepository manualSubs,PaymentReviewRepository reviews,PaymentRefundRepository refunds,PaymentReconciliationRecordRepository reconciliations,FinancialAccountRepository accounts,AccountLedgerEntryRepository ledgers,PaymentGatewayAdapter gateway){this.orders=orders;this.orderHistory=orderHistory;this.methods=methods;this.payments=payments;this.attempts=attempts;this.events=events;this.histories=histories;this.manualSubs=manualSubs;this.reviews=reviews;this.refunds=refunds;this.reconciliations=reconciliations;this.accounts=accounts;this.ledgers=ledgers;this.gateway=gateway;}
 @Transactional public List<PaymentMethodResponse> methods(long account,String orderNumber){ensureMethods();CustomerOrder o=owned(account,orderNumber);return methods.findByActiveTrueOrderByIdAsc().stream().map(m->methodDto(m,o)).toList();}
 @Transactional public PaymentInitiationResult initiate(long account,String orderNumber,PaymentInitiationRequest q){ensureMethods();CustomerOrder o=orders.lockByOrderNumber(orderNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));own(account,o);PaymentMethodConfiguration m=method(q.paymentMethodCode());if(m.getType()!=MethodType.ONLINE_GATEWAY)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","Use the method-specific payment flow.");payable(o,m);PaymentAttempt existing=attempts.findByAccountIdAndOrderIdAndIdempotencyKey(account,o.getId(),q.idempotencyKey()).orElse(null);if(existing!=null){CustomerPayment p=payments.findById(existing.getPaymentId()).orElseThrow();notifyPaymentInitiated(p,m.getDisplayName());return initiationResult(p,existing,"Existing payment attempt returned.");}CustomerPayment p=currentOrNew(o,m);PaymentAttempt a=attempt(p,o,account,q.idempotencyKey(),m);PaymentGatewayAdapter.GatewaySession s=gateway.createSession(new PaymentGatewayAdapter.GatewaySessionRequest(p.getPaymentNumber(),o.getOrderNumber(),p.getAmount(),p.getCurrency(),a.getAttemptNumber(),q.returnTarget()));a.setProvider(s.provider());a.setGatewaySessionId(s.sessionId());a.setExpiresAt(s.expiresAt());a.setStatus(PaymentAttempt.AttemptStatus.SESSION_CREATED);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.PENDING_GATEWAY,"GATEWAY_SESSION","Payment session created.",PaymentStatusHistory.ActorType.SYSTEM,null);p.setGatewayProvider(s.provider());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PENDING_GATEWAY);orders.save(o);notifyPaymentInitiated(p,m.getDisplayName());return initiationResult(p,a,"Complete payment in the secure checkout, then wait for verification.");}
 @Transactional public ManualPaymentResult manual(long account,String orderNumber,ManualPaymentRequest q){ensureMethods();CustomerOrder o=orders.lockByOrderNumber(orderNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));own(account,o);PaymentMethodConfiguration m=method(q.paymentMethodCode());if(m.getType()!=MethodType.BANK_TRANSFER&&m.getType()!=MethodType.MOBILE_FINANCIAL_SERVICE)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","This method does not accept manual references.");payable(o,m);if(manualSubs.findByMethodAndTransactionReference(m.getCode(),q.transactionReference().trim()).isPresent())throw err(HttpStatus.CONFLICT,"PAYMENT_REFERENCE_DUPLICATE","This payment reference was already submitted.");PaymentAttempt existing=attempts.findByAccountIdAndOrderIdAndIdempotencyKey(account,o.getId(),q.idempotencyKey()).orElse(null);if(existing!=null){CustomerPayment p=payments.findById(existing.getPaymentId()).orElseThrow();ManualPaymentSubmission sub=manualSubs.findByPaymentId(p.getId()).orElse(null);notifyManualSubmitted(p,m.getDisplayName());return manualResult(p,sub,"Existing manual payment submission returned.");}CustomerPayment p=currentOrNew(o,m);transition(p,CustomerPayment.PaymentStatus.REVIEW_REQUIRED,"MANUAL_SUBMISSION","Submitted for review.",PaymentStatusHistory.ActorType.CUSTOMER,String.valueOf(account));payments.save(p);PaymentAttempt a=attempt(p,o,account,q.idempotencyKey(),m);a.setStatus(PaymentAttempt.AttemptStatus.REVIEW_REQUIRED);attempts.save(a);ManualPaymentSubmission sub=new ManualPaymentSubmission();sub.setPaymentId(p.getId());sub.setMethod(m.getCode());sub.setTransactionReference(q.transactionReference().trim());sub.setPayerName(trim(q.payerName()));sub.setPayerPhone(trim(q.payerPhone()));sub.setSubmittedAmount(q.submittedAmount());sub.setCustomerNote(trim(q.customerNote()));manualSubs.save(sub);review(p,"MANUAL_PAYMENT_SUBMITTED","Manual payment is awaiting admin review.");o.setPaymentStatus(CustomerOrder.PaymentStatus.REVIEW_REQUIRED);orders.save(o);notifyManualSubmitted(p,m.getDisplayName());return manualResult(p,sub,"Submitted for review. This is not marked paid yet.");}
 @Transactional public CodSelectionResult cod(long account,String orderNumber,CodSelectionRequest q){ensureMethods();CustomerOrder o=orders.lockByOrderNumber(orderNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));own(account,o);PaymentMethodConfiguration m=method("CASH_ON_DELIVERY");payable(o,m);PaymentAttempt existing=attempts.findByAccountIdAndOrderIdAndIdempotencyKey(account,o.getId(),q.idempotencyKey()).orElse(null);CustomerPayment p=existing==null?currentOrNew(o,m):payments.findById(existing.getPaymentId()).orElseThrow();if(existing==null){PaymentAttempt a=attempt(p,o,account,q.idempotencyKey(),m);a.setStatus(PaymentAttempt.AttemptStatus.PENDING);attempts.save(a);transition(p,CustomerPayment.PaymentStatus.COD_PENDING,"COD_SELECTED","Cash will be collected on delivery.",PaymentStatusHistory.ActorType.CUSTOMER,String.valueOf(account));payments.save(p);}o.setPaymentStatus(CustomerOrder.PaymentStatus.COD_PENDING);if(o.getStatus()==CustomerOrder.OrderStatus.PENDING_CONFIRMATION||o.getStatus()==CustomerOrder.OrderStatus.PENDING_PAYMENT){o.setStatus(CustomerOrder.OrderStatus.CONFIRMED);orderStatus(o,"CONFIRMED","Order confirmed for cash on delivery.");}orders.save(o);notifyCodPending(p);return new CodSelectionResult(p.getPaymentNumber(),o.getOrderNumber(),p.getPaymentStatus().name(),o.getStatus().name(),p.getAmount(),p.getCurrency(),"Cash on Delivery selected. The order is not paid until collection and reconciliation.");}
 @Transactional public PaymentStatusResult cancel(long account,String orderNumber){CustomerOrder o=orders.lockByOrderNumber(orderNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));own(account,o);CustomerPayment p=payments.findTopByOrderIdOrderByCreatedAtDesc(o.getId()).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment was not found."));if(p.getPaymentStatus()!=CustomerPayment.PaymentStatus.PENDING_GATEWAY)throw err(HttpStatus.CONFLICT,"PAYMENT_NOT_AVAILABLE","Only an unpaid pending gateway payment can be cancelled.");PaymentAttempt a=attempts.findTopByPaymentIdOrderByAttemptNumberDesc(p.getId()).orElse(null);if(a!=null&&(a.getStatus()==PaymentAttempt.AttemptStatus.CREATED||a.getStatus()==PaymentAttempt.AttemptStatus.SESSION_CREATED||a.getStatus()==PaymentAttempt.AttemptStatus.PENDING)){a.setStatus(PaymentAttempt.AttemptStatus.CANCELLED);attempts.save(a);}transition(p,CustomerPayment.PaymentStatus.CANCELLED,"CUSTOMER_CANCELLED","Pending payment attempt cancelled. The order remains unpaid.",PaymentStatusHistory.ActorType.CUSTOMER,String.valueOf(account));payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.CANCELLED);orders.save(o);return statusDto(p);} @Transactional(readOnly=true) public PaymentStatusResult status(long account,String orderNumber){CustomerOrder o=owned(account,orderNumber);CustomerPayment p=payments.findTopByOrderIdOrderByCreatedAtDesc(o.getId()).orElse(null);return p==null?emptyStatus(o):statusDto(p);}
 @Transactional public WebhookResult webhook(String provider,String body,String signature){if(!gateway.supports(provider))throw err(HttpStatus.FORBIDDEN,"PAYMENT_VERIFICATION_FAILED","Payment provider is not enabled.");PaymentGatewayAdapter.VerificationResult v=gateway.verifyCallback(body,signature);String eventId=StringUtils.hasText(v.eventId())?v.eventId():"INVALID-"+hash(body).substring(0,16);PaymentEvent existing=events.findByProviderAndGatewayEventId(provider,eventId).orElse(null);if(existing!=null){CustomerPayment p=existing.getPaymentId()==null?null:payments.findById(existing.getPaymentId()).orElse(null);return new WebhookResult(provider,eventId,"DUPLICATE",p==null?null:p.getPaymentNumber(),p==null?null:p.getPaymentStatus().name(),null,"Duplicate event ignored.");}PaymentEvent e=new PaymentEvent();e.setProvider(provider);e.setGatewayEventId(eventId);e.setEventType(v.eventType());e.setSignatureValid(v.signatureValid());e.setPayloadHash(hash(body));if(!v.signatureValid()){e.setProcessingStatus(PaymentEvent.ProcessingStatus.REVIEW_REQUIRED);e.setFailureReason("Invalid signature");events.save(e);throw err(HttpStatus.FORBIDDEN,"PAYMENT_VERIFICATION_FAILED","Payment verification failed.");}CustomerPayment p=payments.lockByPaymentNumber(v.paymentNumber()).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment was not found."));e.setPaymentId(p.getId());CustomerOrder o=orders.lockByOrderNumber(p.getOrderNumber()).orElseThrow();try{verifyEvent(p,o,v);PaymentAttempt a=attempts.findByPaymentIdAndAttemptNumber(p.getId(),v.attemptNumber()).orElse(null);if(a!=null){a.setStatus("SUCCEEDED".equals(v.status())?PaymentAttempt.AttemptStatus.SUCCEEDED:PaymentAttempt.AttemptStatus.FAILED);a.setGatewayTransactionId(v.transactionId());attempts.save(a);}if("SUCCEEDED".equals(v.status())){p.setGatewayTransactionId(v.transactionId());transition(p,CustomerPayment.PaymentStatus.VERIFIED,"GATEWAY_WEBHOOK","Payment verified by gateway.",PaymentStatusHistory.ActorType.GATEWAY,provider);postOnce(p,o,"GATEWAY_AUTO");transition(p,CustomerPayment.PaymentStatus.PAID,"ACCOUNTING_POSTED","Payment received and posted.",PaymentStatusHistory.ActorType.SYSTEM,null);p.setPaidAt(Instant.now());o.setPaymentStatus(CustomerOrder.PaymentStatus.PAID);o.setAccountingStatus(CustomerOrder.AccountingStatus.POSTED);if(o.getStatus()==CustomerOrder.OrderStatus.PENDING_CONFIRMATION||o.getStatus()==CustomerOrder.OrderStatus.PENDING_PAYMENT){o.setStatus(CustomerOrder.OrderStatus.CONFIRMED);orderStatus(o,"CONFIRMED","Order confirmed after verified payment.");}orders.save(o);notifyPaymentPaid(p);e.setProcessingStatus(PaymentEvent.ProcessingStatus.PROCESSED);e.setProcessedAt(Instant.now());}else{transition(p,CustomerPayment.PaymentStatus.FAILED,"GATEWAY_WEBHOOK","Payment failed. You may retry.",PaymentStatusHistory.ActorType.GATEWAY,provider);notifyPaymentFailed(p);e.setProcessingStatus(PaymentEvent.ProcessingStatus.PROCESSED);e.setProcessedAt(Instant.now());}payments.save(p);events.save(e);return new WebhookResult(provider,eventId,e.getProcessingStatus().name(),p.getPaymentNumber(),p.getPaymentStatus().name(),o.getStatus().name(),"Webhook processed.");}catch(RuntimeException ex){p.setFailureCode("PAYMENT_REVIEW_REQUIRED");transition(p,CustomerPayment.PaymentStatus.REVIEW_REQUIRED,"WEBHOOK_REVIEW","Payment requires manual review.",PaymentStatusHistory.ActorType.SYSTEM,null);payments.save(p);e.setProcessingStatus(PaymentEvent.ProcessingStatus.REVIEW_REQUIRED);e.setFailureReason(ex.getMessage());events.save(e);throw ex;}}
 @Transactional(readOnly=true) public Page<ReviewSummary> reviews(Pageable p){return reviews.findByStatus(PaymentReview.ReviewStatus.PENDING_REVIEW,p).map(this::reviewDto);} @Transactional public ReviewSummary approveReview(Long reviewId,ReviewDecisionRequest q){PaymentReview r=reviews.findById(reviewId).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Review was not found."));CustomerPayment p=payments.lockById(r.getPaymentId()).orElseThrow();CustomerOrder o=orders.lockByOrderNumber(p.getOrderNumber()).orElseThrow();if(r.getStatus()!=PaymentReview.ReviewStatus.PENDING_REVIEW)throw err(HttpStatus.CONFLICT,"PAYMENT_REVIEW_REQUIRED","Payment review is no longer pending.");if(q.accountId()!=null)p.setCustomerVisibleMessage("Approved after manual review.");transition(p,CustomerPayment.PaymentStatus.VERIFIED,"ADMIN_REVIEW","Payment approved after review.",PaymentStatusHistory.ActorType.ADMIN,"admin");postOnce(p,o,"MANUAL_REVIEW");transition(p,CustomerPayment.PaymentStatus.PAID,"ACCOUNTING_POSTED","Payment received and posted.",PaymentStatusHistory.ActorType.SYSTEM,null);p.setPaidAt(Instant.now());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PAID);o.setAccountingStatus(CustomerOrder.AccountingStatus.POSTED);if(o.getStatus()==CustomerOrder.OrderStatus.PENDING_CONFIRMATION||o.getStatus()==CustomerOrder.OrderStatus.PENDING_PAYMENT){o.setStatus(CustomerOrder.OrderStatus.CONFIRMED);orderStatus(o,"CONFIRMED","Order confirmed after payment review.");}orders.save(o);notifyPaymentPaid(p);r.setStatus(PaymentReview.ReviewStatus.APPROVED);r.setResolution(trim(q.note()));r.setCustomerVisibleNote("Payment approved.");r.setReviewedAt(Instant.now());reviews.save(r);manualSubs.findByPaymentId(p.getId()).ifPresent(s->{s.setStatus(ManualPaymentSubmission.SubmissionStatus.APPROVED);s.setReviewNote("Payment approved.");manualSubs.save(s);});return reviewDto(r);} @Transactional public ReviewSummary rejectReview(Long reviewId,ReviewDecisionRequest q){PaymentReview r=reviews.findById(reviewId).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Review was not found."));CustomerPayment p=payments.lockById(r.getPaymentId()).orElseThrow();transition(p,CustomerPayment.PaymentStatus.FAILED,"ADMIN_REVIEW","Payment rejected after review.",PaymentStatusHistory.ActorType.ADMIN,"admin");p.setFailureCode("PAYMENT_REJECTED");p.setCustomerVisibleMessage(trim(q.note())==null?"Payment was rejected.":trim(q.note()));payments.save(p);r.setStatus(PaymentReview.ReviewStatus.REJECTED);r.setResolution(trim(q.note()));r.setCustomerVisibleNote(p.getCustomerVisibleMessage());r.setReviewedAt(Instant.now());reviews.save(r);manualSubs.findByPaymentId(p.getId()).ifPresent(s->{s.setStatus(ManualPaymentSubmission.SubmissionStatus.REJECTED);s.setReviewNote(p.getCustomerVisibleMessage());manualSubs.save(s);});notifyPaymentRejected(p);return reviewDto(r);} 
 @Transactional public ReconciliationResult reconcile(String paymentNumber,ReconciliationRequest q){CustomerPayment p=payments.lockByPaymentNumber(paymentNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment was not found."));PaymentReconciliationRecord r=reconciliations.findByProviderAndSettlementReference(q.provider(),q.settlementReference()).orElse(null);if(r==null){r=new PaymentReconciliationRecord();r.setPaymentId(p.getId());r.setProvider(q.provider());r.setSettlementReference(q.settlementReference());r.setExpectedAmount(p.getAmount());r.setSettledAmount(q.settledAmount());}if(p.getAmount().compareTo(q.settledAmount())==0){r.setStatus(PaymentReconciliationRecord.ReconciliationStatus.RECONCILED);r.setReconciledAt(Instant.now());if(p.getPaymentStatus()==CustomerPayment.PaymentStatus.COD_PENDING||p.getPaymentStatus()==CustomerPayment.PaymentStatus.CASH_COLLECTED){transition(p,CustomerPayment.PaymentStatus.RECONCILED,"RECONCILIATION","Payment reconciled.",PaymentStatusHistory.ActorType.RECONCILIATION,q.provider());}}else{r.setStatus(PaymentReconciliationRecord.ReconciliationStatus.REVIEW_REQUIRED);r.setMismatchReason("Settlement amount mismatch");transition(p,CustomerPayment.PaymentStatus.REVIEW_REQUIRED,"RECONCILIATION","Payment settlement requires review.",PaymentStatusHistory.ActorType.RECONCILIATION,q.provider());}reconciliations.save(r);payments.save(p);return new ReconciliationResult(p.getPaymentNumber(),r.getStatus().name(),r.getMismatchReason()==null?"Reconciliation recorded.":r.getMismatchReason());}
 @Transactional public RefundResult refund(String paymentNumber,RefundRequest q){CustomerPayment p=payments.lockByPaymentNumber(paymentNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_ATTEMPT_NOT_FOUND","Payment was not found."));if(p.getPaymentStatus()!=CustomerPayment.PaymentStatus.PAID&&p.getPaymentStatus()!=CustomerPayment.PaymentStatus.PARTIALLY_REFUNDED)throw err(HttpStatus.CONFLICT,"PAYMENT_NOT_AVAILABLE","Only paid payments can receive a refund request.");PaymentRefund existing=refunds.findByPaymentIdAndIdempotencyKey(p.getId(),q.idempotencyKey()).orElse(null);if(existing!=null)return new RefundResult(p.getPaymentNumber(),existing.getStatus().name(),existing.getRequestedAmount(),"Existing refund request returned.");BigDecimal refunded=refunds.findByPaymentId(p.getId()).stream().filter(x->x.getStatus()==PaymentRefund.RefundStatus.REFUNDED||x.getStatus()==PaymentRefund.RefundStatus.PARTIALLY_REFUNDED).map(PaymentRefund::getProcessedAmount).filter(Objects::nonNull).reduce(BigDecimal.ZERO,BigDecimal::add);if(q.amount().compareTo(p.getAmount().subtract(refunded))>0)throw err(HttpStatus.UNPROCESSABLE_ENTITY,"PAYMENT_AMOUNT_MISMATCH","Refund amount exceeds refundable balance.");PaymentRefund rf=new PaymentRefund();rf.setPaymentId(p.getId());rf.setIdempotencyKey(q.idempotencyKey());rf.setOriginalAmount(p.getAmount());rf.setRequestedAmount(q.amount());rf.setReason(q.reason().trim());refunds.save(rf);review(p,"REFUND_REQUESTED","Refund request requires backend review.");return new RefundResult(p.getPaymentNumber(),rf.getStatus().name(),rf.getRequestedAmount(),"Refund request recorded for backend review.");}
 private void notifyPaymentInitiated(CustomerPayment p,String method){if(notifications!=null)notifications.paymentInitiated(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getAmount(),method);}
 private void notifyManualSubmitted(CustomerPayment p,String method){if(notifications!=null)notifications.manualSubmitted(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getAmount(),method);}
 private void notifyCodPending(CustomerPayment p){if(notifications!=null)notifications.codPending(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getAmount());}
 private void notifyPaymentPaid(CustomerPayment p){if(notifications!=null)notifications.paymentPaid(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getAmount(),p.getMethodCode());}
 private void notifyPaymentFailed(CustomerPayment p){if(notifications!=null)notifications.paymentFailed(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber(),p.getMethodCode());}
 private void notifyPaymentRejected(CustomerPayment p){if(notifications!=null)notifications.paymentRejected(p.getAccountId(),p.getOrderNumber(),p.getPaymentNumber());}
 private CustomerOrder owned(long account,String n){return orders.findByOrderNumberAndAccountId(n,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));}private void own(long account,CustomerOrder o){if(!Objects.equals(o.getAccountId(),account))throw err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found.");}
 private PaymentMethodConfiguration method(String c){return methods.findByCode(c).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PAYMENT_METHOD_NOT_AVAILABLE","Payment method is not available."));}
 private void payable(CustomerOrder o,PaymentMethodConfiguration m){if(!m.isActive())throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_AVAILABLE","Payment method is not available.");if(!"BDT".equalsIgnoreCase(m.getSupportedCurrency()))throw err(HttpStatus.BAD_REQUEST,"PAYMENT_CURRENCY_MISMATCH","Payment currency is not supported.");if(o.getTotal()==null||o.getTotal().compareTo(BigDecimal.ZERO)<=0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_NOT_AVAILABLE","This order has no payable balance.");if(o.getPaymentStatus()==CustomerOrder.PaymentStatus.PAID)throw err(HttpStatus.CONFLICT,"PAYMENT_ALREADY_PAID","This order is already paid.");if(o.getStatus()==CustomerOrder.OrderStatus.CANCELLED||o.getStatus()==CustomerOrder.OrderStatus.REFUNDED)throw err(HttpStatus.CONFLICT,"PAYMENT_NOT_AVAILABLE","This order is not payable.");if(m.getMinAmount()!=null&&o.getTotal().compareTo(m.getMinAmount())<0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","Order total is below method minimum.");if(m.getMaxAmount()!=null&&o.getTotal().compareTo(m.getMaxAmount())>0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_METHOD_NOT_ELIGIBLE","Order total is above method maximum.");}
 private PaymentMethodResponse methodDto(PaymentMethodConfiguration m,CustomerOrder o){boolean eligible=true;String reason=null;try{payable(o,m);}catch(CustomerAuthException e){eligible=false;reason=e.getMessage();}return new PaymentMethodResponse(m.getCode(),m.getDisplayName(),m.getDescription(),m.getType().name(),m.isActive(),eligible,reason,m.getMinAmount(),m.getMaxAmount(),m.getSupportedCurrency(),m.isRequiresReference(),m.isRequiresProof(),m.getCustomerInstructions(),m.isAutoVerify(),m.isReviewRequired());}
 private CustomerPayment currentOrNew(CustomerOrder o,PaymentMethodConfiguration m){CustomerPayment p=payments.findTopByOrderIdOrderByCreatedAtDesc(o.getId()).filter(x->x.getPaymentStatus()!=CustomerPayment.PaymentStatus.PAID).orElse(null);if(p==null){p=new CustomerPayment();p.setPaymentNumber("TSP-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase());p.setOrderId(o.getId());p.setOrderNumber(o.getOrderNumber());p.setAccountId(o.getAccountId());p.setAmount(o.getTotal().setScale(2,RoundingMode.HALF_UP));p.setCurrency("BDT");}p.setMethodCode(m.getCode());p.setMethodType(m.getType().name());p.setGatewayProvider(m.getProvider());return payments.save(p);}
 private PaymentAttempt attempt(CustomerPayment p,CustomerOrder o,long account,String key,PaymentMethodConfiguration m){PaymentAttempt a=new PaymentAttempt();a.setPaymentId(p.getId());a.setOrderId(o.getId());a.setAccountId(account);a.setAttemptNumber(attempts.findTopByPaymentIdOrderByAttemptNumberDesc(p.getId()).map(x->x.getAttemptNumber()+1).orElse(1));a.setIdempotencyKey(key);a.setMethod(m.getCode());a.setProvider(m.getProvider());a.setAmount(p.getAmount());a.setCurrency(p.getCurrency());a.setStatus(PaymentAttempt.AttemptStatus.CREATED);return attempts.save(a);} 
 private void transition(CustomerPayment p,CustomerPayment.PaymentStatus next,String source,String note,PaymentStatusHistory.ActorType actor,String ref){CustomerPayment.PaymentStatus prev=p.getPaymentStatus();p.setPaymentStatus(next);if(next==CustomerPayment.PaymentStatus.VERIFIED)p.setVerifiedAt(Instant.now());p.setCustomerVisibleMessage(note);PaymentStatusHistory h=new PaymentStatusHistory();h.setPaymentId(p.getId());h.setPreviousStatus(prev==null?null:prev.name());h.setNewStatus(next.name());h.setSource(source);h.setCustomerVisibleNote(note);h.setActorType(actor);h.setActorReference(ref);histories.save(h);} 
 private void postOnce(CustomerPayment p,CustomerOrder o,String source){if(p.getAccountingStatus()==CustomerPayment.AccountingStatus.POSTED)return;String key="CUSTOMER_PAYMENT:"+p.getPaymentNumber();if(payments.existsByPostingKey(key)){p.setAccountingStatus(CustomerPayment.AccountingStatus.POSTED);return;}FinancialAccount a=accounts.findAll().stream().filter(x->x.getStatus()==FinancialAccount.AccountStatus.ACTIVE).findFirst().orElseThrow(()->err(HttpStatus.CONFLICT,"PAYMENT_POSTING_FAILED","No active posting account is configured."));BigDecimal before=a.getCurrentBalance()==null?BigDecimal.ZERO:a.getCurrentBalance();BigDecimal after=before.add(p.getAmount());a.setCurrentBalance(after);accounts.save(a);AccountLedgerEntry e=new AccountLedgerEntry();e.setAccountId(a.getAccountId());e.setEntryType(AccountLedgerEntry.EntryType.PAYMENT_RECEIPT);e.setDirection(Payment.PaymentDirection.RECEIVE);e.setDebitAmount(p.getAmount());e.setCreditAmount(BigDecimal.ZERO);e.setBalanceBefore(before);e.setBalanceAfter(after);e.setReferenceId(o.getId());e.setVoucherNo(p.getPaymentNumber());e.setDescription("Customer order payment posted: "+o.getOrderNumber()+" via "+source);e.setPostedAt(LocalDateTime.now());ledgers.save(e);p.setLedgerEntryId(e.getLedgerEntryId());p.setPostingKey(key);p.setPostedAt(Instant.now());p.setAccountingStatus(CustomerPayment.AccountingStatus.POSTED);}
 private void verifyEvent(CustomerPayment p,CustomerOrder o,PaymentGatewayAdapter.VerificationResult v){if(!Objects.equals(p.getOrderNumber(),v.orderNumber()))throw err(HttpStatus.BAD_REQUEST,"PAYMENT_VERIFICATION_FAILED","Payment order reference does not match.");if(p.getAmount().compareTo(v.amount())!=0)throw err(HttpStatus.BAD_REQUEST,"PAYMENT_AMOUNT_MISMATCH","Payment amount does not match the order total.");if(!p.getCurrency().equalsIgnoreCase(v.currency()))throw err(HttpStatus.BAD_REQUEST,"PAYMENT_CURRENCY_MISMATCH","Payment currency does not match.");if(StringUtils.hasText(v.transactionId())&&payments.findByGatewayTransactionId(v.transactionId()).filter(x->!Objects.equals(x.getId(),p.getId())).isPresent())throw err(HttpStatus.CONFLICT,"PAYMENT_GATEWAY_FAILED","Gateway transaction was already processed.");payable(o,method(p.getMethodCode()));}
 private void review(CustomerPayment p,String reason,String note){PaymentReview r=new PaymentReview();r.setPaymentId(p.getId());r.setReasonCode(reason);r.setCustomerVisibleNote(note);reviews.save(r);}private void orderStatus(CustomerOrder o,String status,String note){CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus(status);h.setCustomerNote(note);orderHistory.save(h);} 
 private PaymentInitiationResult initiationResult(CustomerPayment p,PaymentAttempt a,String msg){return new PaymentInitiationResult(p.getPaymentNumber(),p.getOrderNumber(),p.getPaymentStatus().name(),a.getStatus().name(),p.getMethodCode(),p.getMethodType(),p.getAmount(),p.getCurrency(),a.getProvider(),a.getGatewaySessionId(),a.getGatewaySessionId()==null?null:"techsmart://payments/local-test?sessionId="+a.getGatewaySessionId(),a.getExpiresAt(),msg);} private ManualPaymentResult manualResult(CustomerPayment p,ManualPaymentSubmission s,String msg){return new ManualPaymentResult(p.getPaymentNumber(),p.getOrderNumber(),p.getPaymentStatus().name(),"PENDING_REVIEW",p.getAmount(),p.getCurrency(),s==null?null:s.getTransactionReference(),s==null?null:s.getSubmittedAt(),msg);}private PaymentStatusResult emptyStatus(CustomerOrder o){return new PaymentStatusResult(null,o.getOrderNumber(),o.getPaymentStatus().name(),o.getAccountingStatus().name(),null,null,o.getTotal(),"BDT","Payment has not started.",true,false,List.of(),List.of());}
 private PaymentStatusResult statusDto(CustomerPayment p){List<PaymentAttemptSummary> as=attempts.findByPaymentIdOrderByAttemptNumberAsc(p.getId()).stream().map(a->new PaymentAttemptSummary(a.getAttemptNumber(),a.getStatus().name(),a.getMethod(),a.getProvider(),a.getGatewaySessionId(),a.getExternalReference(),a.getExpiresAt(),a.getCreatedAt())).toList();List<PaymentTimelineEntry> ts=histories.findByPaymentIdOrderByOccurredAtAsc(p.getId()).stream().map(h->new PaymentTimelineEntry(h.getNewStatus(),h.getSource(),h.getCustomerVisibleNote(),h.getOccurredAt(),h.getActorType().name())).toList();boolean retry=p.getPaymentStatus()==CustomerPayment.PaymentStatus.FAILED||p.getPaymentStatus()==CustomerPayment.PaymentStatus.CANCELLED;boolean cancel=p.getPaymentStatus()==CustomerPayment.PaymentStatus.PENDING_GATEWAY;return new PaymentStatusResult(p.getPaymentNumber(),p.getOrderNumber(),p.getPaymentStatus().name(),p.getAccountingStatus().name(),p.getMethodCode(),p.getMethodType(),p.getAmount(),p.getCurrency(),p.getCustomerVisibleMessage(),retry,cancel,as,ts);}private ReviewSummary reviewDto(PaymentReview r){CustomerPayment p=payments.findById(r.getPaymentId()).orElse(null);return new ReviewSummary(r.getId(),p==null?null:p.getPaymentNumber(),p==null?null:p.getOrderNumber(),r.getStatus().name(),r.getReasonCode(),p==null?BigDecimal.ZERO:p.getAmount(),p==null?"BDT":p.getCurrency(),r.getCreatedAt(),r.getCustomerVisibleNote());}
 private void ensureMethods(){upsertMethod("MOBILE_WALLET","Mobile Wallet","Presentation-only Bangladeshi mobile wallet checkout simulation.",MethodType.MOBILE_WALLET,"LOCAL_MOBILE_WALLET_SIM",false,false,true,false);upsertMethod("ONLINE_GATEWAY","Online Payment","Local development hosted checkout simulation.",MethodType.ONLINE_GATEWAY,"LOCAL_TEST",false,false,true,false);upsertMethod("BANK_TRANSFER","Bank Transfer","Submit your bank transfer reference for review.",MethodType.BANK_TRANSFER,null,true,true,false,true);upsertMethod("MOBILE_FINANCIAL_SERVICE","Mobile Transfer","Submit your mobile banking transaction reference for review.",MethodType.MOBILE_FINANCIAL_SERVICE,null,true,true,false,true);upsertMethod("CASH_ON_DELIVERY","Cash on Delivery","Pay cash when your order is delivered and reconciled.",MethodType.CASH_ON_DELIVERY,null,false,false,false,false);}private void upsertMethod(String c,String n,String d,MethodType t,String provider,boolean ref,boolean proof,boolean auto,boolean review){PaymentMethodConfiguration m=methods.findByCode(c).orElseGet(PaymentMethodConfiguration::new);m.setCode(c);m.setDisplayName(n);m.setDescription(d);m.setType(t);m.setProvider(provider);m.setSupportedCurrency("BDT");m.setRequiresReference(ref);m.setRequiresProof(proof);m.setAutoVerify(auto);m.setReviewRequired(review);m.setCustomerInstructions(d);methods.save(m);}private void saveMethod(String c,String n,String d,MethodType t,String provider,boolean ref,boolean proof,boolean auto,boolean review){upsertMethod(c,n,d,t,provider,ref,proof,auto,review);}private String trim(String v){return v==null||v.isBlank()?null:v.trim();}private String hash(String v){try{return HexFormat.of().formatHex(MessageDigest.getInstance("SHA-256").digest(v.getBytes(StandardCharsets.UTF_8)));}catch(Exception e){throw new IllegalStateException(e);}}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} 
}



